# CSV to NDJSON Converter

Here's a complete Node.js script that handles CSV parsing with automatic delimiter detection:

```javascript
#!/usr/bin/env node

/**
 * CSV to NDJSON converter with automatic delimiter detection
 * Supports: comma, tab, semicolon
 * Handles quoted fields with embedded delimiters
 */

const readline = require('readline');

class CSVParser {
  constructor() {
    this.delimiter = null;
    this.headers = [];
    this.lineBuffer = [];
  }

  /**
   * Detect the most likely delimiter from a sample line
   * @param {string} line - Sample line to analyze
   * @returns {string} Detected delimiter
   */
  detectDelimiter(line) {
    const delimiters = [',', '\t', ';'];
    let maxCount = 0;
    let detectedDelimiter = ',';

    for (const delim of delimiters) {
      const count = this.countUnquotedOccurrences(line, delim);
      if (count > maxCount) {
        maxCount = count;
        detectedDelimiter = delim;
      }
    }

    return detectedDelimiter;
  }

  /**
   * Count occurrences of a character outside of quoted fields
   * @param {string} line - Line to analyze
   * @param {string} char - Character to count
   * @returns {number} Count of unquoted occurrences
   */
  countUnquotedOccurrences(line, char) {
    let count = 0;
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const current = line[i];

      if (current === '"') {
        // Check if it's an escaped quote
        if (inQuotes && line[i + 1] === '"') {
          i += 2;
          continue;
        }
        inQuotes = !inQuotes;
      } else if (current === char && !inQuotes) {
        count++;
      }

      i++;
    }

    return count;
  }

  /**
   * Parse a CSV line respecting quoted fields
   * @param {string} line - CSV line to parse
   * @returns {string[]} Array of parsed fields
   */
  parseLine(line) {
    const fields = [];
    let currentField = '';
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const current = line[i];
      const next = line[i + 1];

      if (current === '"') {
        if (inQuotes && next === '"') {
          // Escaped quote
          currentField += '"';
          i += 2;
          continue;
        } else {
          // Toggle quote state
          inQuotes = !inQuotes;
          i++;
          continue;
        }
      }

      if (current === this.delimiter && !inQuotes) {
        // Field delimiter found
        fields.push(currentField.trim());
        currentField = '';
        i++;
        continue;
      }

      currentField += current;
      i++;
    }

    // Add the last field
    fields.push(currentField.trim());

    return fields;
  }

  /**
   * Process a complete line (may span multiple input lines if quoted)
   * @param {string} line - Input line
   * @returns {object|null} Parsed object or null if line is incomplete
   */
  processLine(line) {
    this.lineBuffer.push(line);
    const fullLine = this.lineBuffer.join('\n');

    // Check if line is complete (not inside unclosed quotes)
    if (!this.isLineComplete(fullLine)) {
      return null;
    }

    // Reset buffer after processing
    this.lineBuffer = [];

    // Detect delimiter on first line
    if (!this.delimiter) {
      this.delimiter = this.detectDelimiter(fullLine);
    }

    const fields = this.parseLine(fullLine);

    // First line is headers
    if (this.headers.length === 0) {
      this.headers = fields;
      return null; // Don't output headers
    }

    // Create object from headers and fields
    const record = {};
    for (let i = 0; i < this.headers.length; i++) {
      record[this.headers[i]] = fields[i] || '';
    }

    return record;
  }

  /**
   * Check if a line has balanced quotes
   * @param {string} line - Line to check
   * @returns {boolean} True if quotes are balanced
   */
  isLineComplete(line) {
    let inQuotes = false;
    let i = 0;

    while (i < line.length) {
      const current = line[i];
      const next = line[i + 1];

      if (current === '"') {
        if (inQuotes && next === '"') {
          // Escaped quote
          i += 2;
          continue;
        }
        inQuotes = !inQuotes;
      }
      i++;
    }

    return !inQuotes;
  }

  /**
   * Flush any remaining buffered content
   * @returns {object|null} Last record if any
   */
  flush() {
    if (this.lineBuffer.length > 0) {
      const fullLine = this.lineBuffer.join('\n');
      this.lineBuffer = [];

      if (fullLine.trim().length > 0) {
        const fields = this.parseLine(fullLine);
        const record = {};
        for (let i = 0; i < this.headers.length; i++) {
          record[this.headers[i]] = fields[i] || '';
        }
        return record;
      }
    }

    return null;
  }
}

async function main() {
  const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    terminal: false,
  });

  const parser = new CSVParser();
  let lineCount = 0;
  let errorCount = 0;

  rl.on('line', (line) => {
    try {
      const record = parser.processLine(line);
      if (record !== null) {
        console.log(JSON.stringify(record));
      }
    } catch (error) {
      errorCount++;
      console.error(
        `Error parsing line ${lineCount + 1}: ${error.message}`,
        { fd: 2 }
      );
    }
    lineCount++;
  });

  rl.on('close', () => {
    try {
      const lastRecord = parser.flush();
      if (lastRecord !== null) {
        console.log(JSON.stringify(lastRecord));
      }

      if (errorCount > 0) {
        console.error(`Completed with ${errorCount} errors`, { fd: 2 });
      }
    } catch (error) {
      console.error(`Final error: ${error.message}`, { fd: 2 });
      process.exit(1);
    }
  });

  rl.on('error', (error) => {
    console.error(`Input error: ${error.message}`, { fd: 2 });
    process.exit(1);
  });
}

main().catch((error) => {
  console.error(`Fatal error: ${error.message}`, { fd: 2 });
  process.exit(1);
});
```

## Usage Examples

### Basic usage with comma-delimited CSV:

```bash
cat data.csv | node csv-to-ndjson.js
```

### Tab-delimited input:

```bash
cat data.tsv | node csv-to-ndjson.js
```

### Semicolon-delimited input:

```bash
cat data.csv | node csv-to-ndjson.js
```

### Test with inline CSV:

```bash
cat << 'EOF' | node csv-to-ndjson.js
Name,Email,Age
"John Doe",john@example.com,30
"Jane Smith",jane@example.com,28
EOF
```

